#!/usr/bin/env bash
set -euo pipefail

SCRIPT_DIR="$(cd -- "$(dirname -- "${BASH_SOURCE[0]}")" && pwd)"
APPLY_PATCH_DIR="$(cd -- "${SCRIPT_DIR}/.." && pwd)"
ARTIFACTS_DIR="${APPLY_PATCH_DIR}/Artifacts"
TARGET_DIR="${MSP_CODEX_APPLY_PATCH_TARGET_DIR:-${APPLY_PATCH_DIR}/.build/target}"
HEADER_DIR="${APPLY_PATCH_DIR}/Bridge/include"
OUTPUT="${MSP_CODEX_APPLY_PATCH_XCFRAMEWORK:-${ARTIFACTS_DIR}/MSPCodexApplyPatchBridge.xcframework}"
RECEIPT="${OUTPUT}/BUILD_RECEIPT.txt"
PROVENANCE="${APPLY_PATCH_DIR}/Source/CODEX_SOURCE_PROVENANCE.txt"
STRIP_DEBUG_SYMBOLS="${MSP_CODEX_APPLY_PATCH_STRIP_DEBUG_SYMBOLS:-1}"

required_targets=(
  "aarch64-apple-ios"
  "aarch64-apple-ios-sim"
)

for target in "${required_targets[@]}"; do
  if ! rustup target list --installed | grep -Fx "${target}" >/dev/null; then
    echo "Missing Rust target: ${target}" >&2
    echo "Install it with: rustup target add ${target}" >&2
    exit 1
  fi
done

for target in "${required_targets[@]}"; do
  MSP_CODEX_APPLY_PATCH_TARGET="${target}" \
    MSP_CODEX_APPLY_PATCH_TARGET_DIR="${TARGET_DIR}" \
    "${SCRIPT_DIR}/build-rust-bridge.sh"
done

rm -rf "${OUTPUT}"
xcodebuild -create-xcframework \
  -library "${TARGET_DIR}/aarch64-apple-ios/release/libmsp_codex_apply_patch_bridge.a" \
  -headers "${HEADER_DIR}" \
  -library "${TARGET_DIR}/aarch64-apple-ios-sim/release/libmsp_codex_apply_patch_bridge.a" \
  -headers "${HEADER_DIR}" \
  -output "${OUTPUT}"

if [[ "${STRIP_DEBUG_SYMBOLS}" != "0" ]]; then
  xcrun strip -S "${OUTPUT}/ios-arm64/libmsp_codex_apply_patch_bridge.a"
  xcrun strip -S "${OUTPUT}/ios-arm64-simulator/libmsp_codex_apply_patch_bridge.a"
fi

source_git_head="$(
  awk -F= '$1 == "source_git_head" { print $2; exit }' "${PROVENANCE}"
)"
source_scope="$(
  awk -F= '$1 == "source_scope" { print $2; exit }' "${PROVENANCE}"
)"

{
  echo "# Generated by Scripts/build-xcframework.sh"
  echo "format=msp-codex-apply-patch-artifact-receipt-v1"
  echo "artifact=MSPCodexApplyPatchBridge.xcframework"
  echo "source_provenance=Source/CODEX_SOURCE_PROVENANCE.txt"
  echo "source_git_head=${source_git_head}"
  echo "source_scope=${source_scope}"
  echo "build_script=Scripts/build-xcframework.sh"
  echo "build_profile=release"
  echo "rust_targets=aarch64-apple-ios,aarch64-apple-ios-sim"
  echo "rustc_version=$(rustc --version)"
  echo "cargo_version=$(cargo --version)"
  echo "xcodebuild_version=$(xcodebuild -version | tr '\n' ' ' | sed 's/[[:space:]]*$//')"
  echo "strip_command=xcrun strip -S"
  echo "debug_symbols=stripped"
  echo "path_remap_policy=required"
  echo "artifact_files_begin"
  find "${OUTPUT}" -type f ! -name "BUILD_RECEIPT.txt" -print | LC_ALL=C sort | while IFS= read -r file; do
    relative_path="${file#"${OUTPUT}/"}"
    digest="$(shasum -a 256 "${file}" | awk '{ print $1 }')"
    size="$(wc -c < "${file}" | tr -d '[:space:]')"
    echo "sha256=${digest} size=${size} path=${relative_path}"
  done
  echo "artifact_files_end"
} > "${RECEIPT}"

echo "Built ${OUTPUT}"
